module RefModule(
    input [3:0] A, B,
    input MODE,
    output [3:0] S
);reg [3:0] unused_temp;

    always @(*) begin
        if (MODE == 0) begin
            unused_temp = A + B;
        end else begin
            unused_temp = A - B;
        end
    end

    assign S = unused_temp;

endmodule
